import { mkdir, readFile, writeFile } from "node:fs/promises";
import { createHash } from "node:crypto";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { SCHEMA_PATHS, CANONICAL_SCHEMA_PATHS } from "../src/lib/schemas.js";

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const outputPath = resolve(repoRoot, "functions/_generated/diligenceSchemaBundle.js");

function sha256(value) {
  return createHash("sha256").update(value, "utf8").digest("hex");
}

function toFilePath(schemaPath) {
  return resolve(repoRoot, schemaPath.replace(/^\//, ""));
}

async function readSchema(schemaId, schemaPath) {
  const raw = await readFile(toFilePath(schemaPath), "utf8");
  const parsed = JSON.parse(raw);

  return {
    schema_id: schemaId,
    path: schemaPath,
    title: parsed.title || schemaId,
    sha256: sha256(raw),
    schema: parsed
  };
}

async function main() {
  const schemas = {};

  for (const [schemaId, schemaPath] of Object.entries(SCHEMA_PATHS)) {
    schemas[schemaId] = await readSchema(schemaId, schemaPath);
  }

  const bundle = {
    generated_at: new Date().toISOString(),
    schemas,
    canonical_schema_paths: CANONICAL_SCHEMA_PATHS
  };

  const source = `// Generated by scripts/generate-diligence-schema-bundle.mjs. Do not edit by hand.\n\nexport const DILIGENCE_SCHEMA_BUNDLE = Object.freeze(${JSON.stringify(bundle, null, 2)});\n`;

  await mkdir(dirname(outputPath), { recursive: true });
  await writeFile(outputPath, source, "utf8");

  console.log(`Generated ${outputPath}`);
  console.log(`Schema count: ${Object.keys(schemas).length}`);
}

main().catch((error) => {
  console.error("Failed to generate Diligence schema bundle.");
  console.error(error?.stack ?? error?.message ?? error);
  process.exitCode = 1;
});
